import{_ as r}from"./plugin-vue_export-helper.21dcd24c.js";import{r as n,c as F,a,b as p,F as i,d as o,e,o as s}from"./app.30963f6b.js";const c={},h=o('<h1 id="bff-\u6A21\u5F0F-backend-for-frontend" tabindex="-1"><a class="header-anchor" href="#bff-\u6A21\u5F0F-backend-for-frontend" aria-hidden="true">#</a> BFF \u6A21\u5F0F \uFF08Backend For Frontend\uFF09</h1><blockquote><p>\u9762\u8BD5\u548C\u7B80\u5386\u90FD\u63D0\u5230\u4E86\uFF0C\u6240\u4EE5\u6765\u5B66\u4E60\u804A\u804A</p><p>PS:</p><p>\u4F60\u5E94\u8BE5\u8BB0\u4F4F\uFF0CBFF \u662F\u5BA2\u6237\u7AEF\u548C\u670D\u52A1\u4E4B\u95F4\u7684\u8F6C\u6362\u5C42\u3002 \u5F53\u6570\u636E\u4ECE\u670D\u52A1\u7AEFAPI \u8FD4\u56DE\u65F6\uFF0C\u5176\u76EE\u7684\u662F\u5C06\u5176\u8F6C\u6362\u4E3A\u5BA2\u6237\u7AEF\u5E94\u7528\u7A0B\u5E8F\u6307\u5B9A\u7684\u6570\u636E\u7C7B\u578B\u3002 \u907F\u514DBFF \u903B\u8F91\u91CD\u590D\u2014\u2014\u9700\u8981\u6CE8\u610F\u7684\u4E00\u4E2A\u5173\u952E\u70B9\u662F\uFF0C\u5355\u4E2ABFF \u5E94\u8BE5\u6EE1\u8DB3\u7279\u5B9A\u7684\u7528\u6237\u4F53\u9A8C\uFF0C\u800C\u4E0D\u662F\u8BBE\u5907\u7C7B\u578B\u3002 \u4F8B\u5982\uFF0C\u5927\u591A\u6570\u65F6\u5019\uFF0C\u6240\u6709\u79FB\u52A8\u8BBE\u5907\uFF08iOS\u3001Android \u7B49\uFF09\u5171\u4EAB\u76F8\u540C\u7684\u7528\u6237\u4F53\u9A8C\u3002</p></blockquote><blockquote><p>\u53C2\u8003\uFF1A</p><p>https://perspectives.mobilelive.ca/</p><p>https://www.infoq.cn/article/4hjplbxo1xktefxzpqz8</p></blockquote><p>\u8BBE\u60F3\u4E00\u4E2A\u573A\u666F\uFF0C\u4F60\u9700\u8981\u4F7F\u7528\u5FAE\u670D\u52A1\u6784\u5EFA\u7535\u5B50\u5546\u52A1\u5E94\u7528\u7A0B\u5E8F\u3002\u4F60\u53EF\u4EE5\u4E3A\u5BA2\u6237\u3001\u8BA2\u5355\u3001\u4EA7\u54C1\u3001\u8D2D\u7269\u8F66\u7B49\u63D0\u4F9B\u5FAE\u670D\u52A1\uFF0C\u5FAE\u670D\u52A1\u66B4\u9732 API \u7ED9\u524D\u7AEF\u4F7F\u7528\u3002</p><p>\u4F46\u662F\uFF0C\u5FAE\u670D\u52A1\u63D0\u4F9B\u7ED9\u524D\u7AEF\u7684\u6570\u636E\u53EF\u80FD\u4E0D\u4F1A\u6309\u7167\u524D\u7AEF\u9700\u8981\u7684\u65B9\u5F0F\u8FDB\u884C\u7F16\u6392\u6216\u8FC7\u6EE4\u3002</p><p>\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u524D\u7AEF\u9700\u8981\u4E00\u4E9B\u903B\u8F91\u6765\u91CD\u65B0\u5904\u7406\u8FD9\u4E9B\u6570\u636E\uFF0C\u540C\u65F6\u5728\u7528\u6237\u7AEF\u4F7F\u7528\u8FD9\u6837\u7684\u903B\u8F91\u4F1A\u5360\u7528\u66F4\u591A\u7684\u6D4F\u89C8\u5668\u8D44\u6E90\u3002</p><p>BFF \u5C06\u6267\u884C\u4EE5\u4E0B\u64CD\u4F5C\uFF1A</p><ul><li>\u8C03\u7528\u76F8\u5173\u7684\u5FAE\u670D\u52A1 API \u5E76\u83B7\u53D6\u6240\u9700\u6570\u636E</li><li>\u6839\u636E\u524D\u7AEF\u5C55\u73B0\u6765\u5904\u7406\u6570\u636E</li><li>\u5C06\u683C\u5F0F\u5316\u540E\u7684\u6570\u636E\u53D1\u9001\u5230\u524D\u7AEF</li></ul><p>\u56E0\u6B64\uFF0C<strong>\u524D\u7AEF\u5C06\u6709\u66F4\u5C11\u7684\u903B\u8F91\uFF0CBFF \u6709\u52A9\u4E8E\u7B80\u5316\u6570\u636E\u5C55\u793A\uFF0C\u5E76\u4E3A\u524D\u7AEF\u63D0\u4F9B\u4E00\u4E2A\u76EE\u7684\u660E\u786E\u7684\u63A5\u53E3\u3002</strong></p><h2 id="\u5B83\u5982\u4F55\u9002\u7528\u4E8E\u7535\u5B50\u5546\u52A1" tabindex="-1"><a class="header-anchor" href="#\u5B83\u5982\u4F55\u9002\u7528\u4E8E\u7535\u5B50\u5546\u52A1" aria-hidden="true">#</a> \u5B83\u5982\u4F55\u9002\u7528\u4E8E\u7535\u5B50\u5546\u52A1\uFF1F</h2><p>\u4E0B\u56FE\u663E\u793A\u4E86\u6BCF\u4E2A\u5FAE\u670D\u52A1\u5982\u4F55\u901A\u8FC7 BFF \u4E0E\u524D\u7AEF\u8FDE\u63A5\u3002</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202204071933563.png" alt="img"></p><h2 id="bff-\u7684\u89D2\u8272" tabindex="-1"><a class="header-anchor" href="#bff-\u7684\u89D2\u8272" aria-hidden="true">#</a> BFF \u7684\u89D2\u8272</h2><p>\u6B63\u5982\u6211\u4EEC\u5DF2\u7ECF\u63A2\u8BA8\u8FC7\u7684\uFF0CBFF \u5145\u5F53\u524D\u7AEF\u548C\u5FAE\u670D\u52A1\u4E4B\u95F4\u7684\u7B80\u5355\u63A5\u53E3\u3002\u7406\u60F3\u60C5\u51B5\u4E0B\uFF0C\u524D\u7AEF\u56E2\u961F\u4E5F\u5C06\u8D1F\u8D23\u7BA1\u7406 BFF\u3002</p><p>\u4E00\u4E2A BFF \u53EA\u5173\u6CE8\u4E00\u4E2A UI\uFF0C\u800C\u4E14\u53EA\u5173\u6CE8\u90A3\u4E2A UI\u3002\u56E0\u6B64\uFF0C\u5B83\u5C06\u5E2E\u52A9\u6211\u4EEC\u4FDD\u6301\u524D\u7AEF\u7684\u7B80\u5355\u6027\uFF0C\u5E76\u901A\u8FC7\u540E\u7AEF\u8F93\u51FA\u7684\u7EDF\u4E00\u7684\u6570\u636E\u683C\u5F0F\u3002</p><p>\u8FD9\u5C31\u5F15\u51FA\u4E86\u4E0B\u4E00\u4E2A\u95EE\u9898\u3002\u6211\u4EEC\u80FD\u4E3A\u591A\u4E2A\u7528\u6237\u754C\u9762\u63D0\u4F9B\u591A\u4E2A BFF \u5417\uFF1F\u6211\u4EEC\u5C06\u5728\u540E\u9762\u56DE\u7B54\u8FD9\u4E2A\u95EE\u9898\u3002</p><h3 id="\u8FD9\u4F1A\u589E\u52A0\u5EF6\u8FDF\u5417" tabindex="-1"><a class="header-anchor" href="#\u8FD9\u4F1A\u589E\u52A0\u5EF6\u8FDF\u5417" aria-hidden="true">#</a> \u8FD9\u4F1A\u589E\u52A0\u5EF6\u8FDF\u5417\uFF1F</h3><p>\u73B0\u5728\u6211\u4EEC\u77E5\u9053 BFF \u7C7B\u4F3C\u4E8E\u5BA2\u6237\u7AEF\u548C\u5176\u4ED6\u5916\u90E8 API\u3001\u670D\u52A1\u7B49\u4E4B\u95F4\u7684\u4EE3\u7406\u670D\u52A1\u5668\u3002\u5982\u679C\u8BF7\u6C42\u5FC5\u987B\u901A\u8FC7\u53E6\u4E00\u4E2A\u7EC4\u4EF6\uFF0C\u5B83\u80AF\u5B9A\u4F1A\u589E\u52A0\u5EF6\u8FDF\u3002\u4F46\u662F\uFF0C\u5982\u679C\u6D4F\u89C8\u5668\u9700\u8981\u5904\u7406\u591A\u4E2A\u672A\u9488\u5BF9\u524D\u7AEF\u4F18\u5316\u7684\u670D\u52A1\uFF0C\u90A3\u4E48\u4E0E\u6D4F\u89C8\u5668\u7684\u9AD8\u8D44\u6E90\u4F7F\u7528\u7387\u76F8\u6BD4\uFF0CBFF \u5EF6\u8FDF\u53EF\u4EE5\u5FFD\u7565\u4E0D\u8BA1\u3002</p><blockquote><p>\u6784\u5EFA BFF \u5141\u8BB8\u4F60\u667A\u80FD\u5730\u5BF9\u5176\u4ED6\u540E\u7AEF / \u5FAE\u670D\u52A1\u8FDB\u884C\u6279\u5904\u7406\u8C03\u7528\uFF0C\u5E76\u4E00\u6B21\u8FD4\u56DE\u6240\u6709\u6570\u636E\uFF0C\u6216\u8005\u901A\u8FC7\u8F6C\u6362\u548C\u683C\u5F0F\u5316\u6570\u636E\u6765\u8FD4\u56DE\u66F4\u65B9\u4FBF\u7684\u5C55\u73B0\u5F62\u5F0F\u3002</p></blockquote><p>\u8FD9\u5BF9\u4E8E 2G \u6216 3G \u7F51\u7EDC\u4E0A\u7684\u79FB\u52A8\u5BA2\u6237\u7AEF\u975E\u5E38\u6709\u7528\uFF0C\u56E0\u4E3A\u5728\u8FD9\u4E9B\u7F51\u7EDC\u4E0A\u5EFA\u7ACB\u8FDE\u63A5\u53EF\u80FD\u9700\u8981\u51E0\u79D2\u949F\uFF08\u6216\u66F4\u957F\u65F6\u95F4\uFF09\u3002</p><h3 id="\u5E94\u7528\u7A0B\u5E8F\u4F55\u65F6\u4F7F\u7528-bff" tabindex="-1"><a class="header-anchor" href="#\u5E94\u7528\u7A0B\u5E8F\u4F55\u65F6\u4F7F\u7528-bff" aria-hidden="true">#</a> \u5E94\u7528\u7A0B\u5E8F\u4F55\u65F6\u4F7F\u7528 BFF</h3>',21),d=e("\u4E0E\u8BB8\u591A\u5176\u4ED6\u6A21\u5F0F\u4E00\u6837\uFF0C\u5728\u5E94\u7528\u7A0B\u5E8F\u4E2D\u4F7F\u7528 BFF \u53D6\u51B3\u4E8E\u4F60\u8BA1\u5212\u9075\u5FAA\u7684\u4E0A\u4E0B\u6587\u548C\u4F53\u7CFB\u7ED3\u6784\u3002\u5982\u679C\u4F60\u7684\u5E94\u7528\u7A0B\u5E8F\u662F\u4E00\u4E2A\u7B80\u5355\u7684\u5355\u7247\u5E94\u7528\u7A0B\u5E8F\uFF08\u8BD1\u8005\u6CE8\uFF1A"),l={href:"https://www.zhihu.com/question/37905345/answer/75170829",target:"_blank",rel:"noopener noreferrer"},B=e("monolithic app"),g=e("\uFF0C\u5355\u7247\u8F6F\u4EF6\u6307\u975E\u6A21\u5757\u5316\u7684\u8F6F\u4EF6\uFF0C\u4E5F\u662F\u4E00\u79CD\u8BBE\u8BA1\u601D\u60F3\u3002\u5B83\u5C06 UI\u3001\u6570\u636E\u3001\u903B\u8F91\u7B49\u5168\u90E8\u505A\u6210\u4E00\u6574\u5757\uFF0C\u4EE5\u4E00\u4E2A\u5B8C\u5168\u6574\u4F53\u7684\u65B9\u5F0F\u5B9E\u73B0\uFF0C\u901A\u5E38\u4F1A\u76F4\u63A5\u4ECE\u5F00\u59CB\u5230\u7ED3\u675F\u5B8C\u6210\u4E00\u4E2A\u590D\u6742\u4EFB\u52A1\u7684\u6BCF\u4E00\u5C0F\u6B65\uFF0C\u540C\u65F6\u7531\u81EA\u5DF1\u72EC\u7ACB\u5BF9\u6240\u6709\u7684\u6570\u636E\u8FDB\u884C\u7BA1\u7406\uFF09\uFF0C\u90A3\u4E48 BFF \u662F\u4E0D\u5FC5\u8981\u7684\uFF0C\u5B83\u51E0\u4E4E\u6BEB\u65E0\u4EF7\u503C\u3002"),u=o('<p>\u4F46\u662F\uFF0C\u5982\u679C\u4F60\u7684\u5E94\u7528\u7A0B\u5E8F\u4F9D\u8D56\u4E8E\u5FAE\u670D\u52A1\uFF0C\u5E76\u4E14\u4F7F\u7528\u8BB8\u591A\u5916\u90E8 API \u548C\u5176\u4ED6\u670D\u52A1\uFF0C\u90A3\u4E48\u6700\u597D\u4F7F\u7528 BFF \u6765\u7B80\u5316\u6570\u636E\u6D41\uFF0C\u5E76\u4E3A\u4F60\u7684\u5E94\u7528\u7A0B\u5E8F\u5E26\u6765\u66F4\u9AD8\u7684\u6548\u7387\u3002</p><p>\u6B64\u5916\uFF0C\u5982\u679C\u4F60\u7684\u5E94\u7528\u7A0B\u5E8F\u9700\u8981\u4E3A\u7279\u5B9A\u7684\u524D\u7AEF\u63A5\u53E3\u5F00\u53D1\u4F18\u5316\u7684\u540E\u7AEF\uFF0C\u6216\u8005\u4F60\u7684\u5BA2\u6237\u7AEF\u9700\u8981\u4F7F\u7528\u5728\u540E\u7AEF\u8FDB\u884C\u5927\u91CF\u805A\u5408\u7684\u6570\u636E\uFF0C\u90A3\u4E48 BFF \u662F\u4E00\u4E2A\u5408\u9002\u7684\u9009\u9879\u3002</p><p>\u63D0\u793A\uFF1A\u5206\u5E03\u5F0F\u8BBE\u8BA1\u9700\u8981\u4E0D\u540C\u79CD\u7C7B\u7684\u4EE3\u7801\u534F\u4F5C\u5DE5\u5177\u3002\u4F7F\u7528 Bit\uFF08Github\uFF09\u5728\u5355\u4E2A\u7EC4\u4EF6\u4E0A\u8FDB\u884C\u534F\u4F5C\uFF0C\u8FD9\u4E9B\u7EC4\u4EF6\u53EF\u4EE5\u8DE8\u4EE3\u7801\u4ED3\u5E93\u5171\u4EAB\u5E76\u72EC\u7ACB\u5F00\u53D1\u3002</p><p>\u4FDD\u6301\u4F60\u7684\u4EE3\u7801\u4ED3\u5E93\u53EF\u6269\u5C55\u6027\u3001\u53EF\u7EF4\u62A4\u6027\u548C\u59CB\u7EC8\u540C\u6B65\u3002</p><h2 id="\u6211\u4EEC\u80FD\u6709\u591A\u4E2A-bff-\u5417" tabindex="-1"><a class="header-anchor" href="#\u6211\u4EEC\u80FD\u6709\u591A\u4E2A-bff-\u5417" aria-hidden="true">#</a> \u6211\u4EEC\u80FD\u6709\u591A\u4E2A BFF \u5417\uFF1F</h2><p>\u5F53\u7136\u53EF\u4EE5\uFF01\u8FD9\u5C31\u662F BFF \u7684\u610F\u4E49\u6240\u5728\u3002</p><p>\u6CA1\u6709 BFF \u7684\u4F20\u7EDF\u5E94\u7528\u7A0B\u5E8F\u5BF9\u4E8E<strong>\u5404\u79CD\u5BA2\u6237\u7AEF\u53EA\u6709\u4E00\u4E2A API \u7F51\u5173</strong>\uFF0C\u5982\u4E0B\u6240\u793A\uFF0C</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202204071949274.png" alt="img"></p><p>\u7136\u800C\uFF0C\u62E5\u6709 BFF \u7684\u76EE\u7684\u662F\u4E3A\u5BA2\u6237\u7AEF\u63D0\u4F9B\u4E00\u4E2A\u53EF\u8FDE\u63A5\u7684\u96C6\u4E2D\u63A5\u53E3\u3002\u4F8B\u5982\uFF0C\u79FB\u52A8 UI \u7684\u6570\u636E\u6D88\u8017\u53EF\u80FD\u4E0D\u540C\u4E8E\u6D4F\u89C8\u5668\u7684\u6570\u636E\u6D88\u8017\u3002\u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u4E3A\u4E86\u66F4\u597D\u5730\u5C55\u793A\u6570\u636E\uFF0C\u53EF\u4EE5\u4F7F\u7528\u4E24\u4E2A BFF\u3002\u591A\u4E2A BFF \u7684\u5E94\u7528\u7A0B\u5E8F\u5982\u4E0B\u56FE\u6240\u793A\uFF0C</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202204071950431.png" alt="img"></p><p>\u5982\u4F60\u6240\u89C1\uFF0C\u6BCF\u79CD\u5BA2\u6237\u7AEF\u90FD\u6709\u4E00\u4E2A BFF\uFF0C\u5B83\u5C06\u6709\u52A9\u4E8E\u4F18\u5316\u670D\u52A1\uFF08Sa\u3001Sb\u2026Sn\uFF09\u7684\u54CD\u5E94\u3002</p><h2 id="bff-\u7684\u4F18\u70B9" tabindex="-1"><a class="header-anchor" href="#bff-\u7684\u4F18\u70B9" aria-hidden="true">#</a> BFF \u7684\u4F18\u70B9</h2><p>\u62E5\u6709 BFF \u7684\u51E0\u4E2A\u4F18\u70B9\uFF1A</p><ul><li><strong>\u5173\u6CE8\u70B9\u5206\u79BB</strong>\u2014\u2014\u524D\u7AEF\u9700\u6C42\u5C06\u4E0E\u540E\u7AEF\u5173\u6CE8\u70B9\u5206\u79BB\uFF0C\u4FBF\u4E8E\u7EF4\u62A4\u3002</li><li><strong>\u66F4\u5BB9\u6613\u7EF4\u62A4\u548C\u4FEE\u6539 API</strong>\u2014\u2014\u5BA2\u6237\u7AEF\u5E94\u7528\u7A0B\u5E8F\u5BF9 API \u7ED3\u6784\u4E86\u89E3\u8F83\u5C11\uFF0C\u8FD9\u5C06\u4F7F\u5176\u5BF9 API \u4E2D\u7684\u66F4\u6539\u66F4\u6709\u5F39\u6027\u3002</li><li><strong>\u66F4\u597D\u7684\u524D\u7AEF\u9519\u8BEF\u5904\u7406</strong>\u2014\u2014\u5927\u90E8\u5206\u65F6\u95F4\uFF0C\u670D\u52A1\u5668\u9519\u8BEF\u5BF9\u524D\u7AEF\u7528\u6237\u662F\u6CA1\u6709\u610F\u4E49\u7684\u3002BFF \u53EF\u4EE5\u6620\u5C04\u51FA\u9700\u8981\u663E\u793A\u7ED9\u7528\u6237\u7684\u9519\u8BEF\uFF0C\u800C\u4E0D\u662F\u76F4\u63A5\u8FD4\u56DE\u670D\u52A1\u5668\u9519\u8BEF\uFF0C\u8FD9\u5C06\u6539\u5584\u7528\u6237\u4F53\u9A8C\u3002</li><li><strong>\u591A\u79CD\u8BBE\u5907\u7C7B\u578B\u53EF\u4EE5\u5E76\u884C\u8C03\u7528\u540E\u7AEF</strong>\u2014\u2014\u5F53\u6D4F\u89C8\u5668\u5411 BFF \u53D1\u51FA\u8BF7\u6C42\u65F6\uFF0C\u79FB\u52A8\u8BBE\u5907\u4E5F\u53EF\u4EE5\u8FD9\u6837\u505A\u3002\u8FD9\u5C06\u6709\u52A9\u4E8E\u66F4\u5FEB\u5730\u83B7\u5F97\u76F8\u5E94\u670D\u52A1\u7684\u54CD\u5E94\u3002</li><li><strong>\u66F4\u597D\u7684\u5B89\u5168\u6027</strong>\u2014\u2014\u67D0\u4E9B\u654F\u611F\u4FE1\u606F\u53EF\u4EE5\u88AB\u9690\u85CF\uFF0C\u5E76\u4E14\u5728\u5411\u524D\u7AEF\u8FD4\u56DE\u54CD\u5E94\u65F6\u53EF\u4EE5\u5FFD\u7565\u4E0D\u5FC5\u8981\u7684\u6570\u636E\u3002\u8FD9\u79CD\u62BD\u8C61\u5C06\u4F7F\u653B\u51FB\u8005\u66F4\u96BE\u4EE5\u5E94\u7528\u7A0B\u5E8F\u4E3A\u76EE\u6807\u3002</li><li><strong>\u5171\u4EAB\u7EC4\u4EF6\u7684\u56E2\u961F\u6240\u6709\u6743</strong>\u2014\u2014\u5E94\u7528\u7A0B\u5E8F\u7684\u4E0D\u540C\u90E8\u5206\u53EF\u4EE5\u7531\u4E0D\u540C\u7684\u56E2\u961F\u8F7B\u677E\u5904\u7406\u3002\u524D\u7AEF\u56E2\u961F\u53EF\u4EE5\u5171\u4EAB\u5BA2\u6237\u7AEF\u5E94\u7528\u7A0B\u5E8F\u53CA\u5176\u5E95\u5C42\u8D44\u6E90\u6D88\u8017\u5C42\u7684\u6240\u6709\u6743\uFF0C\u4ECE\u800C\u63D0\u9AD8\u5F00\u53D1\u901F\u5EA6\u3002\u4E0B\u56FE\u663E\u793A\u4E86\u56E2\u961F\u5212\u5206 BFF \u7684\u4F8B\u5B50\u3002</li></ul><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202204072005445.png" alt="img"></p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202204072009823.jpeg" alt="\u56FE\u7247\u63CF\u8FF0"></p><h2 id="\u5728\u5B9E\u8DF5\u4E2D\u9075\u5FAA\u7684\u6700\u4F73\u5B9E\u8DF5" tabindex="-1"><a class="header-anchor" href="#\u5728\u5B9E\u8DF5\u4E2D\u9075\u5FAA\u7684\u6700\u4F73\u5B9E\u8DF5" aria-hidden="true">#</a> \u5728\u5B9E\u8DF5\u4E2D\u9075\u5FAA\u7684\u6700\u4F73\u5B9E\u8DF5</h2><p>\u5230\u76EE\u524D\u4E3A\u6B62\uFF0C\u6211\u4EEC\u6240\u770B\u5230\u7684\u4E00\u5207\u90FD\u662F\u60CA\u4EBA\u7684\uFF01\u4F46\u662F\uFF0CBFF \u662F\u5426\u53EF\u4EE5\u9632\u6545\u969C\uFF1F</p><p>\u7B54\u6848\u662F\u5426\u5B9A\u7684\uFF01\u548C\u5176\u4ED6\u6280\u672F\u6216\u6A21\u5F0F\u4E00\u6837\uFF0C\u5373\u4F7F\u662F BFF \u4E5F\u6709\u9677\u9631\u3002\u4E3A\u4E86\u907F\u514D\u8FD9\u4E9B\uFF0C\u6211\u4EEC\u5FC5\u987B\u9075\u5FAA\u4E00\u4E9B\u6700\u4F73\u5B9E\u8DF5\u3002\u4E0B\u9762\u5217\u51FA\u4E86\u4E00\u4E9B\u8981\u9075\u5FAA\u7684\u6700\u4F73\u505A\u6CD5\u3002</p><ul><li><strong>\u907F\u514D\u4F7F\u7528\u81EA\u5305\u542B\u7684\u5927\u800C\u5168\u7684 API \u5B9E\u73B0 BFF</strong>\u2014\u2014\u4F60\u7684\u81EA\u5305\u542B API \u5E94\u8BE5\u4F4D\u4E8E\u5FAE\u670D\u52A1\u5C42\u3002\u5927\u591A\u6570\u5F00\u53D1\u4EBA\u5458\u5FD8\u8BB0\u4E86\u8FD9\u4E00\u70B9\uFF0C\u4E5F\u5F00\u59CB\u5728 BFF \u4E2D\u5B9E\u73B0\u670D\u52A1\u7EA7\u522B API\u3002\u4F60\u5E94\u8BE5\u8BB0\u4F4F\uFF0CBFF \u662F\u5BA2\u6237\u7AEF\u548C\u670D\u52A1\u4E4B\u95F4\u7684\u8F6C\u6362\u5C42\u3002\u5F53\u6570\u636E\u4ECE\u670D\u52A1\u7AEF API \u8FD4\u56DE\u65F6\uFF0C\u5176\u76EE\u7684\u662F\u5C06\u5176\u8F6C\u6362\u4E3A\u5BA2\u6237\u7AEF\u5E94\u7528\u7A0B\u5E8F\u6307\u5B9A\u7684\u6570\u636E\u7C7B\u578B\u3002</li><li><strong>\u907F\u514D BFF \u903B\u8F91\u91CD\u590D</strong>\u2014\u2014\u9700\u8981\u6CE8\u610F\u7684\u4E00\u4E2A\u5173\u952E\u70B9\u662F\uFF0C\u5355\u4E2A BFF \u5E94\u8BE5\u6EE1\u8DB3\u7279\u5B9A\u7684\u7528\u6237\u4F53\u9A8C\uFF0C\u800C\u4E0D\u662F\u8BBE\u5907\u7C7B\u578B\u3002\u4F8B\u5982\uFF0C\u5927\u591A\u6570\u65F6\u5019\uFF0C\u6240\u6709\u79FB\u52A8\u8BBE\u5907\uFF08iOS\u3001Android \u7B49\uFF09\u5171\u4EAB\u76F8\u540C\u7684\u7528\u6237\u4F53\u9A8C\u3002\u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u6240\u6709\u8FD9\u4E9B\u64CD\u4F5C\u7CFB\u7EDF\u7684\u4E00\u4E2A BFF \u5C31\u8DB3\u591F\u4E86\u3002iOS \u4E0D\u9700\u8981\u5355\u72EC\u7684 BFF\uFF0CAndroid \u4E5F\u4E0D\u9700\u8981\u5355\u72EC\u7684 BFF\u3002</li><li><strong>\u907F\u514D\u8FC7\u5EA6\u4F9D\u8D56 BFF</strong>\u2014\u2014BFF \u53EA\u662F\u4E00\u4E2A\u8F6C\u6362\u5C42\u3002\u662F\u7684\uFF0C\u5B83\u4E5F\u4E3A\u5E94\u7528\u7A0B\u5E8F\u63D0\u4F9B\u4E86\u4E00\u5B9A\u7A0B\u5EA6\u7684\u5B89\u5168\u6027\u3002\u4F46\u662F\uFF0C\u4F60\u4E0D\u5E94\u8BE5\u8FC7\u5206\u4F9D\u8D56\u5B83\u3002\u4F60\u7684 API \u5C42\u548C\u524D\u7AEF\u5C42\u5E94\u8BE5\u8D1F\u8D23\u6240\u6709\u7684\u529F\u80FD\u548C\u5B89\u5168\u65B9\u9762\uFF0C\u800C\u4E0D\u7BA1\u662F\u5426\u5B58\u5728 BFF\u3002\u56E0\u4E3A BFF \u53EA\u662F\u586B\u8865\u4E00\u4E2A\u7A7A\u767D\uFF0C\u800C\u4E0D\u662F\u5411\u5E94\u7528\u7A0B\u5E8F\u6DFB\u52A0\u4EFB\u4F55\u529F\u80FD\u6216\u670D\u52A1\u3002</li></ul><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><p>BFF \u6A21\u5F0F\u4E0D\u4EC5\u6709\u52A9\u4E8E\u5F00\u53D1\uFF0C\u800C\u4E14\u6709\u52A9\u4E8E\u6781\u5927\u5730\u6539\u5584\u7528\u6237\u4F53\u9A8C\u3002\u56E0\u6B64\uFF0C\u5728\u4FDD\u6301 BFF \u4E13\u6CE8\u4E8E\u5176\u524D\u7AEF\u7684\u540C\u65F6\uFF0C\u8003\u8651\u6570\u636E\u4F18\u5316\u548C\u805A\u5408\u662F\u975E\u5E38\u91CD\u8981\u7684\u3002</p><p>\u6B64\u5916\uFF0C\u5982\u679C\u4F60\u4EE5\u524D\u6CA1\u6709\u4F7F\u7528\u8FC7 BFF \u6A21\u5F0F\uFF0C\u73B0\u5728\u662F\u65F6\u5019\u5F00\u59CB\u4E86\u3002</p><h3 id="\u4E00\u4E9B\u7F51\u7EDC\u89C2\u70B9" tabindex="-1"><a class="header-anchor" href="#\u4E00\u4E9B\u7F51\u7EDC\u89C2\u70B9" aria-hidden="true">#</a> \u4E00\u4E9B\u7F51\u7EDC\u89C2\u70B9</h3><blockquote><p>BFF\u5B58\u5728\u7684\u552F\u4E00\u539F\u56E0\uFF0C\u662F\u540E\u7AEF\u4E0D\u613F\u610F\u7EF4\u62A4\u53D8\u52A8\u6700\u9891\u7E41\uFF0C\u6570\u91CF\u6700\u591A\u7684\u4E1A\u52A1\u63A5\u53E3\u8FD9\u79CD\u810F\u6D3B\u7D2F\u6D3B\uFF0C \u53EA\u613F\u610F\u7EF4\u62A4\u53D8\u66F4\u8F83\u5C11\u7684\u6838\u5FC3\u670D\u52A1\uFF0C\u524D\u7AEF\u65E0\u5948\uFF0C\u53EA\u80FD\u81EA\u5DF1\u541E\u4E0B\u82E6\u6C34\uFF0C\u7F8E\u540D\u5176\u66F0\uFF1ABFF\uFF0C\u5B9E\u9645\u4E0A\u662F\u4E1A\u52A1\u4E0A\u524D\u7AEF\u8BDD\u8BED\u6743\u7684\u5F31\u52BF\u7684\u4F53\u73B0\u3002</p><p>BFF\u5C42\u5176\u5B9E\u7406\u89E3\u6210\u4E00\u4E2A\u529F\u80FD\u5355\u4E00\u7684\u7F51\u5173\u5C31 OK \u4E86</p></blockquote>',25);function f(m,b){const t=n("ExternalLinkIcon");return s(),F(i,null,[h,a("p",null,[d,a("a",l,[B,p(t)]),g]),u],64)}var x=r(c,[["render",f],["__file","BFF.html.vue"]]);export{x as default};
